UPDATE tb_user_wallet
SET balance = balance - #{amount},
    total_consume = total_consume + #{amount},
    version = version + 1,
    update_time = NOW()
WHERE user_id = #{userId}
  AND balance >= #{amount}
  AND version = #{version}
  AND deleted = 0

UPDATE tb_user_wallet
SET balance = balance - #{amount},
    frozen_balance = frozen_balance + #{amount},
    version = version + 1,
    update_time = NOW()
WHERE user_id = #{userId}
  AND balance >= #{amount}
  AND version = #{version}
  AND deleted = 0
